import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const y=JSON.parse('{"title":"海晏堂与十二生肖兽首","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/haiyan-tang.md","filePath":"landmarks/yuanmingyuan/haiyan-tang.md","lastUpdated":1784720050000}'),r={name:"landmarks/yuanmingyuan/haiyan-tang.md"};function i(d,t,s,o,g,h){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="海晏堂与十二生肖兽首" tabindex="-1">海晏堂与十二生肖兽首 <a class="header-anchor" href="#海晏堂与十二生肖兽首" aria-label="Permalink to &quot;海晏堂与十二生肖兽首&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1598117407983-b3a39ee9747a?w=1200&amp;q=80" alt="海晏堂遗址"></p><blockquote><p>&quot;海晏&quot;者，河清海晏，天下太平。十二尊兽首曾在这里报时，如今它们散落在世界各地，等待着最后的团圆。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>海晏堂是长春园<a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a>中体量最大的建筑，建成于乾隆二十四年（1759年），取&quot;河清海晏、国泰民安&quot;之意命名。楼体坐东朝西，上下两层十一开间，红砖墙身镶嵌汉白玉石雕，是西洋楼中西洋形式与中国意趣融合的代表。</p><p>海晏堂之所以举世闻名，缘于楼前那组<strong>十二生肖兽首人身铜像喷泉</strong>：十二尊铜像分列楼前八字形水池两侧，按十二时辰依次喷水报时，正午时分十二兽首同时喷涌，蔚为奇观。</p><p>这组铜像由意大利传教士郎世宁设计、法国传教士蒋友仁监修水力、中国宫廷工匠铸造，是18世纪中西工艺合作的巅峰之作。1860年英法联军劫掠圆明园时，兽首被强行锯断掠走，从此流散海外。一个半世纪以来，兽首的每一次回归都牵动国人之心，它们已成为流失海外中国文物的象征。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建成年代</strong></td><td style="text-align:left;">乾隆二十四年（1759年）</td></tr><tr><td style="text-align:left;"><strong>建筑规模</strong></td><td style="text-align:left;">上下两层，面阔十一开间，西洋楼最大建筑</td></tr><tr><td style="text-align:left;"><strong>设计监造</strong></td><td style="text-align:left;">郎世宁设计，蒋友仁监修水力，清宫造办处铸造</td></tr><tr><td style="text-align:left;"><strong>核心景观</strong></td><td style="text-align:left;">十二生肖兽首人身铜像水力钟喷泉</td></tr><tr><td style="text-align:left;"><strong>现状</strong></td><td style="text-align:left;">主楼仅存砖石残墙与台阶；兽首七尊回归、一尊存疑、四尊失考</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="海晏堂主楼" tabindex="-1">海晏堂主楼 <a class="header-anchor" href="#海晏堂主楼" aria-label="Permalink to &quot;海晏堂主楼&quot;">​</a></h3><p>海晏堂主楼为巴洛克风格的两层楼建筑，面阔十一间，是皇帝宴请外藩、观赏水法的场所。楼前设大型蓄水池（俗称&quot;锡海&quot;），以锡板焊接而成，可容水180余吨，为楼前喷泉群供水。</p><p>1860年后主楼焚毁，今存高大的砖石残墙与汉白玉台阶、石栏，仍可辨识当年的恢宏尺度——仅台阶就宽达数十米，拾级而上可想见楼阁之高。</p><h3 id="十二生肖水力钟" tabindex="-1">十二生肖水力钟 <a class="header-anchor" href="#十二生肖水力钟" aria-label="Permalink to &quot;十二生肖水力钟&quot;">​</a></h3><p>楼前八字形叠落式喷水池两侧，各置六尊<strong>兽首人身铜像</strong>：</p><ul><li>南岸：鼠、虎、龙、马、猴、狗</li><li>北岸：牛、兔、蛇、羊、鸡、猪</li></ul><p>铜像人身着中式袍服，兽首以写实手法铸成，高约50厘米，重约3-4公斤，为宫廷精铸铜胎。每到一个时辰（两小时），对应兽首即口中喷水；<strong>正午午时，十二兽首同时喷涌</strong>，水柱直冲数尺，声震全园——这是一座以生肖报时的&quot;水力钟&quot;。</p><h3 id="十二兽首今何在" tabindex="-1">十二兽首今何在 <a class="header-anchor" href="#十二兽首今何在" aria-label="Permalink to &quot;十二兽首今何在&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">兽首</th><th style="text-align:left;">对应时辰</th><th style="text-align:left;">现状</th></tr></thead><tbody><tr><td style="text-align:center;">鼠首</td><td style="text-align:left;">子时（23:00-1:00）</td><td style="text-align:left;">已回归，2013年法国皮诺家族捐赠，现藏中国国家博物馆</td></tr><tr><td style="text-align:center;">牛首</td><td style="text-align:left;">丑时（1:00-3:00）</td><td style="text-align:left;">已回归，2000年保利集团竞拍购回，现藏保利艺术博物馆</td></tr><tr><td style="text-align:center;">虎首</td><td style="text-align:left;">寅时（3:00-5:00）</td><td style="text-align:left;">已回归，2000年保利集团竞拍购回，现藏保利艺术博物馆</td></tr><tr><td style="text-align:center;">兔首</td><td style="text-align:left;">卯时（5:00-7:00）</td><td style="text-align:left;">已回归，2013年法国皮诺家族捐赠，现藏中国国家博物馆</td></tr><tr><td style="text-align:center;">龙首</td><td style="text-align:left;">辰时（7:00-9:00）</td><td style="text-align:left;">据传存于台湾，尚未公开证实</td></tr><tr><td style="text-align:center;">蛇首</td><td style="text-align:left;">巳时（9:00-11:00）</td><td style="text-align:left;">下落不明</td></tr><tr><td style="text-align:center;">马首</td><td style="text-align:left;">午时（11:00-13:00）</td><td style="text-align:left;">已回归，2019年何鸿燊捐赠，现藏圆明园正觉寺</td></tr><tr><td style="text-align:center;">羊首</td><td style="text-align:left;">未时（13:00-15:00）</td><td style="text-align:left;">下落不明</td></tr><tr><td style="text-align:center;">猴首</td><td style="text-align:left;">申时（15:00-17:00）</td><td style="text-align:left;">已回归，2000年保利集团竞拍购回，现藏保利艺术博物馆</td></tr><tr><td style="text-align:center;">鸡首</td><td style="text-align:left;">酉时（17:00-19:00）</td><td style="text-align:left;">下落不明</td></tr><tr><td style="text-align:center;">狗首</td><td style="text-align:left;">戌时（19:00-21:00）</td><td style="text-align:left;">下落不明</td></tr><tr><td style="text-align:center;">猪首</td><td style="text-align:left;">亥时（21:00-23:00）</td><td style="text-align:left;">已回归，2003年何鸿燊购得捐赠，现藏保利艺术博物馆</td></tr></tbody></table><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="三国工匠共铸一钟" tabindex="-1">三国工匠共铸一钟 <a class="header-anchor" href="#三国工匠共铸一钟" aria-label="Permalink to &quot;三国工匠共铸一钟&quot;">​</a></h3><p>十二生肖兽首的设计与制造堪称&quot;国际合作&quot;：意大利人郎世宁依据中国生肖提出造型方案，以西洋写实手法绘制图样；法国人蒋友仁解决供水与水力计时机关；最后由清宫造办处中国工匠以失蜡法铸铜、精细錾刻而成。</p><p>兽首的毛发、皱纹纤毫毕现，兼具西洋写实与中国神韵，至今被视为清代宫廷铸造工艺的最高水平。</p><h3 id="流失与回归" tabindex="-1">流失与回归 <a class="header-anchor" href="#流失与回归" aria-label="Permalink to &quot;流失与回归&quot;">​</a></h3><p>1860年10月，英法联军冲入海晏堂，将十二尊兽首锯下掠走，自此流散四方。此后百余年间，兽首辗转于拍卖行与私人藏家之手。</p><p>2000年春，牛、虎、猴三首现身香港拍卖会，保利集团以重金购回，开启兽首回归之路；2013年法国皮诺家族将鼠、兔二首无偿捐赠中国；2019年11月，何鸿燊捐赠的<strong>马首</strong>正式回归圆明园，安奉于<a href="/beijing-travel-guide/landmarks/yuanmingyuan/qichun-yuan.html">绮春园正觉寺</a>——这是第一尊回归圆明园本址的兽首。</p><p>龙首据传存于台湾；蛇、羊、鸡、狗四首至今下落不明。兽首能否全部团圆，仍是几代中国人的牵挂。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>海晏堂残墙与台阶</strong>：西洋楼最大建筑的遗存，感受当年的宏阔尺度</li><li><strong>八字形喷水池遗址</strong>：对照说明牌想象十二兽首依次报时的场景</li><li><strong>马首回归展（正觉寺内）</strong>：目前唯一回归圆明园本址的兽首真品，必看</li><li><strong>锡海遗址</strong>：楼后巨大的锡制蓄水池遗迹，喷泉系统的&quot;心脏&quot;</li><li><strong>兽首复制品与图片展</strong>：园内设有兽首复原模型与历史照片，便于对照想象</li><li><strong>汉白玉栏杆雕花</strong>：台阶残存石栏上中西合璧的纹样细节</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>海晏堂位于<strong>西洋楼遗址区</strong>内，需另购15元遗址区门票</li><li><strong>看真品兽首</strong>：马首藏于绮春园正觉寺展厅；鼠、兔首在中国国家博物馆；牛、虎、猴、猪首在保利艺术博物馆</li><li>建议先读展板上的兽首分布图，再参观残址，历史感更完整</li><li>游览顺序建议：方外观 → <strong>海晏堂</strong> → <a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a>，沿西洋楼主线东行</li><li>请勿触摸遗址石构件与展品；展厅内禁用闪光灯</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a>——三园全貌与游览路线</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a>——海晏堂北侧的喷泉主景</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a>——海晏堂所属的西式景区</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/qichun-yuan.html">绮春园</a>——马首安奉地正觉寺所在</li><li><a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>——1860年劫掠始末</li></ul><hr><p><strong>📍 位置</strong>：长春园北部，西洋楼景区，大水法西侧、方外观东侧 <strong>⏱️ 建议游览</strong>：30-40分钟（含展厅另需30分钟） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a></p>',35)])])}const x=e(r,[["render",i]]);export{y as __pageData,x as default};
